private static final long serialVersionUID = 1L;

protected String smtpUsername = null;
protected String smtpPassword = null;

public $SchemaName$SMWarUtil() {
	super();
}

public void sendEMailToUser(
	I$SecSchemaName$SecUserObj toUser,
	String msgSubject,
	String msgBody )
throws
	IOException,
	MessagingException,
	NamingException
{

	final String S_ProcName = "sendEMailToUser";

	Properties props = System.getProperties();

	Context ctx = new InitialContext();

String smtpHost = (String)ctx.lookup( "java:comp/env/$SchemaName$SmtpHost");
if( ( smtpHost == null ) || ( smtpHost.length() <= 0 ) ) {
	throw new CFLibNullArgumentException( getClass(),
			S_ProcName,
			0,
			"JNDI lookup for $SchemaName$SmtpHost" );
}

String smtpStrPort = (String)ctx.lookup( "java:comp/env/$SchemaName$SmtpPort");
if( ( smtpStrPort == null ) || ( smtpStrPort.length() <= 0 ) ) {
	throw new CFLibNullArgumentException( getClass(),
			S_ProcName,
			0,
			"JNDI lookup for $SchemaName$SmtpPort" );
}

int smtpPort = Integer.parseInt( smtpStrPort );

String smtpEnableSMTPS = (String)ctx.lookup( "java:comp/env/$SchemaName$SmtpEnableSMTPS");
if( ( smtpEnableSMTPS == null ) || ( smtpEnableSMTPS.length() <= 0 ) ) {
	throw new CFLibNullArgumentException( getClass(),
			S_ProcName,
			0,
			"JNDI lookup for $SchemaName$SmtpEnableSMTPS" );
}

boolean enableSMTPS;
if( smtpEnableSMTPS.equals( "true" ) ) {
	enableSMTPS = true;
}
else if( smtpEnableSMTPS.equals( "false" ) ) {
	enableSMTPS = false;
}
else {
	throw new CFLibUsageException( getClass(),
		S_ProcName,
		"$SchemaName$SmtpEnableSMTPS must be true or false, not \"" + smtpEnableSMTPS + "\"" );
}

String smtpEmailFrom = (String)ctx.lookup( "java:comp/env/$SchemaName$SmtpEmailFrom");
if( ( smtpEmailFrom == null ) || ( smtpEmailFrom.length() <= 0 ) ) {
	throw new CFLibNullArgumentException( getClass(),
			S_ProcName,
			0,
			"JNDI lookup for $SchemaName$SmtpEmailFrom" );
}

smtpUsername = (String)ctx.lookup( "java:comp/env/$SchemaName$SmtpUsername");
if( ( smtpUsername == null ) || ( smtpUsername.length() <= 0 ) ) {
	throw new CFLibNullArgumentException( getClass(),
			S_ProcName,
			0,
			"JNDI lookup for $SchemaName$SmtpUsername" );
}

smtpPassword = (String)ctx.lookup( "java:comp/env/$SchemaName$SmtpPassword");
if( ( smtpPassword == null ) || ( smtpPassword.length() <= 0 ) ) {
	throw new CFLibNullArgumentException( getClass(),
			S_ProcName,
			0,
			"JNDI lookup for $SchemaName$SmtpPassword" );
}

Session emailSess = Session.getInstance( props,
	new Authenticator() {
		protected PasswordAuthentication getPasswordAuthentication() {
			return new PasswordAuthentication( smtpUsername, smtpPassword );
		}
	} );

	MimeMessage msg = new MimeMessage( emailSess );
	msg.setFrom( new InternetAddress( smtpEmailFrom ) );
	InternetAddress mailTo[] = InternetAddress.parse( toUser.getRequiredEMailAddress(), false );
	msg.setRecipient( Message.RecipientType.TO, mailTo[0] );
	msg.setSubject( ( msgSubject != null ) ? msgSubject : "No subject" );
	msg.setSentDate( new Date() );
	msg.setContent( msgBody, "text/html" );
	msg.saveChanges();

	if( enableSMTPS ) {
		// As per suggestion fromm http://stackoverflow.com/questions/10005937/javamail-sender-address-rejected-access-denied
		Transport transport = emailSess.getTransport( "smtps" );
		transport.connect( smtpHost, smtpPort, smtpUsername, smtpPassword );
		transport.sendMessage( msg, msg.getAllRecipients() );
		transport.close();
	}
	else {
		Transport.send( msg );
	}
}
